        mgmfrm3_spec;
        experimental = true,
        init = mgmfrm3_raw_initial,
        seed = 20260704,
        ndraws = 1,
        warmup = 0,
        chains = 1,
        step_size = 0.02,
        max_depth = 2,
        metric = :unit,
    )
